async function main() {
  console.log(`Total updates: ${updates.length}`);
  let count = 0;
  const fails = [];
  for (const item of updates) {
    const wc = item.description.trim().split(/\s+/).length;
    const ml = item.metaDescription.length;
    console.log(`${item.slug}: desc=${wc}w, meta=${ml}c ${wc < 250 ? ' ❌ SHORT' : ''}${ml < 130 || ml > 155 ? ' ❌ META' : ''}`);
    if (wc < 250 || ml < 130 || ml > 155) {
      console.log('  -> Skipping (validation failed)');
      continue;
    }
    try {
      await prisma.product.update({
        where: { slug: item.slug },
        data: {
          description: item.description,
          metaDescription: item.metaDescription
        }
      });
      count++;
      console.log('  -> OK');
    } catch (e) {
      console.log('  -> SKIP:', e.message.substring(0, 80));
      fails.push(item.slug);
    }
  }
  console.log(`\nUpdated: ${count}/${updates.length}`);
  if (fails.length) console.log('Failed:', fails.join(', '));
}

main().then(() => prisma.$disconnect()).catch(e => { console.error(e); prisma.$disconnect(); });
